mapper.sql:
ot.level = 'PLATFORM' AND ot.company_id = #{platformCompanyId}
AND UPPER(ot.status) = UPPER(#{status})
AND ( LOWER(ot.name) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(COALESCE(ot.description, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') OR LOWER(COALESCE(ot.department_type_code, '')) LIKE CONCAT('%', LOWER(#{keyword}), '%') )
